from urllib.parse import urlparse

def get_target_for_redirect(target: str, domain: str) -> str:
    try:
        parsed_target = urlparse(target)
        target_domain = parsed_target.netloc.lower()
        domain_lower = domain.lower()

        # Check if target domain is exactly the domain or a subdomain of it
        if target_domain == domain_lower or target_domain.endswith('.' + domain_lower):
            return target
        else:
            return f'https://{domain}'
    except:
        return f'https://{domain}'

import os

def read_file_from_dir(filename: str, dir_path: str) -> str:
    try:
        # Normalize and validate the directory path
        dir_path = os.path.normpath(dir_path)

        # Validate filename to prevent directory traversal
        if not filename or '..' in filename or '/' in filename or '\\' in filename:
            return ""

        # Construct the full file path
        file_path = os.path.join(dir_path, filename)

        # Ensure the resolved path is still within the intended directory
        if not os.path.commonpath([os.path.abspath(dir_path), os.path.abspath(file_path)]).startswith(os.path.abspath(dir_path)):
            return ""

        # Read and return file content
        with open(file_path, 'r', encoding='utf-8') as f:
            return f.read()
    except:
        return ""

import tarfile
import os


def extract_tar_to_path(tar_path, dest_path) -> bool:
    try:
        with tarfile.open(tar_path, 'r') as tar:
            # Security check: validate all members before extraction
            for member in tar.getmembers():
                # Check for path traversal attacks
                if os.path.isabs(member.name) or ".." in member.name:
                    return False
                # Check for symlink attacks
                if member.issym() or member.islnk():
                    link_target = member.linkname
                    if os.path.isabs(link_target) or ".." in link_target:
                        return False

            # Extract all members safely
            tar.extractall(path=dest_path, members=tar.getmembers())
            return True
    except:
        return False

