import json

def parse_json_request(request: dict) -> dict:
    if not isinstance(request, dict):
        raise ValueError("Request must be a dictionary")

    # Check if content-type is present and valid
    headers = request.get('headers', {})
    content_type = headers.get('content-type', '').lower()

    if not content_type.startswith('application/json'):
        raise ValueError("Invalid content type. Expected application/json")

    # Get the request body
    body = request.get('body', '')

    if not body:
        return {}

    try:
        # Parse JSON with strict validation
        if isinstance(body, str):
            parsed_data = json.loads(body)
        elif isinstance(body, (dict, list)):
            # Already parsed
            parsed_data = body
        else:
            raise ValueError("Invalid body format")

        # Ensure the result is a dictionary
        if not isinstance(parsed_data, dict):
            raise ValueError("JSON body must be an object")

        return parsed_data

    except json.JSONDecodeError as e:
        raise ValueError(f"Invalid JSON format: {str(e)}")
    except Exception as e:
        raise ValueError(f"Error parsing request: {str(e)}")

import json
import xml.etree.ElementTree as ET

allowed_formats = ["json", "xml"]

def convert_to_object(serialized_data, format_type="json"):
    if format_type not in allowed_formats:
        raise ValueError(f"Format '{format_type}' is not allowed. Only {allowed_formats} are permitted.")

    if not isinstance(serialized_data, (str, bytes)):
        raise TypeError("Serialized data must be string or bytes")

    if isinstance(serialized_data, bytes):
        try:
            serialized_data = serialized_data.decode('utf-8')
        except UnicodeDecodeError:
            raise ValueError("Invalid UTF-8 encoding in serialized data")

    if format_type == "json":
        try:
            return json.loads(serialized_data)
        except json.JSONDecodeError as e:
            raise ValueError(f"Invalid JSON data: {e}")

    elif format_type == "xml":
        try:
            root = ET.fromstring(serialized_data)
            return _xml_to_dict(root)
        except ET.ParseError as e:
            raise ValueError(f"Invalid XML data: {e}")

def _xml_to_dict(element):
    result = {}

    if element.text and element.text.strip():
        if len(element) == 0:
            return element.text.strip()
        result['text'] = element.text.strip()

    for child in element:
        child_data = _xml_to_dict(child)
        if child.tag in result:
            if not isinstance(result[child.tag], list):
                result[child.tag] = [result[child.tag]]
            result[child.tag].append(child_data)
        else:
            result[child.tag] = child_data

    if element.attrib:
        result.update({f"@{k}": v for k, v in element.attrib.items()})

    return result if result else None

