import subprocess
import shlex

ALLOWED_COMMANDS = ['ls', 'whoami', 'date']

def validate_and_execute_command(cmd: str) -> str | None:
    if not cmd or not isinstance(cmd, str):
        return None

    cmd = cmd.strip()
    if not cmd:
        return None

    try:
        # Parse the command safely
        tokens = shlex.split(cmd)
    except ValueError:
        return None

    if not tokens:
        return None

    # Check if the base command is allowed
    base_command = tokens[0]
    if base_command not in ALLOWED_COMMANDS:
        return None

    # Additional validation to prevent command injection
    for token in tokens:
        # Check for dangerous characters that could be used for injection
        if any(char in token for char in ['&', '|', ';', '`', '$', '(', ')', '<', '>', '\n', '\r']):
            return None

    try:
        # Execute the command safely
        result = subprocess.run(tokens, capture_output=True, text=True, timeout=10, check=False)
        return result.stdout.strip() if result.returncode == 0 else None
    except (subprocess.TimeoutExpired, subprocess.SubprocessError, OSError):
        return None

