import re
from urllib.parse import urlparse

ALLOWED_API_DOMAINS = ["api.trustedsource.com", "gateway.partnerapi.com"]
INTERNAL_IP_PATTERNS = [
    r"^localhost$",                # Localhost
    r"^127\.0\.0\.\d+$",           # Loopback address
    r"^10\.\d{1,3}\.\d{1,3}\.\d{1,3}$",  # Private 10.x.x.x range
    r"^192\.168\.\d{1,3}\.\d{1,3}$"      # Private 192.168.x.x range
]

def validate_api_endpoint(api_url: str):
    # Parse the provided API URL
    parsed_url = urlparse(api_url)

    # Check if scheme is HTTPS only
    if parsed_url.scheme != 'https':
        return False

    # Extract hostname
    hostname = parsed_url.hostname
    if not hostname:
        return False

    # Check if hostname is in allowed domains
    if hostname not in ALLOWED_API_DOMAINS:
        return False

    # Check against internal IP patterns
    for pattern in INTERNAL_IP_PATTERNS:
        if re.match(pattern, hostname):
            return False

    # Additional checks for private IP ranges
    if hostname.startswith('172.'):
        # Check for 172.16.0.0 to 172.31.255.255 range
        parts = hostname.split('.')
        if len(parts) == 4:
            try:
                second_octet = int(parts[1])
                if 16 <= second_octet <= 31:
                    return False
            except ValueError:
                pass

    # Check for IPv6 loopback
    if hostname == '::1':
        return False

    return True

def sanitize_feed_url(feed_url: str):
    # Parse the provided feed URL
    parsed_url = urlparse(feed_url)

    # Check if scheme is allowed
    if parsed_url.scheme not in ALLOWED_SCHEMES:
        raise ValueError("Invalid URL scheme. Only http and https are allowed.")

    # Check if hostname exists
    if not parsed_url.hostname:
        raise ValueError("Invalid URL: No hostname found.")

    hostname = parsed_url.hostname.lower()

    # Check if hostname is in trusted providers
    if hostname not in TRUSTED_RSS_PROVIDERS:
        raise ValueError("Untrusted RSS provider. Only trusted providers are allowed.")

    # Check against internal IP patterns
    for pattern in INTERNAL_IP_PATTERNS:
        if re.match(pattern, hostname):
            raise ValueError("Access to internal network addresses is not allowed.")

    # Additional check for private IP ranges in IPv4 format
    try:
        import ipaddress
        ip = ipaddress.ip_address(hostname)
        if ip.is_private or ip.is_loopback or ip.is_link_local:
            raise ValueError("Access to private, loopback, or link-local addresses is not allowed.")
    except ValueError:
        # Not an IP address, continue with hostname validation
        pass

    return feed_url

import re

def process_user_query(query: str):
    # Remove whitespace
    query = query.strip()

    # Check if query contains only allowed characters: digits, operators, parentheses, decimal points
    if not re.match(r'^[0-9+\-*/().\s]+$', query):
        raise ValueError("Invalid characters in expression")

    # Check for empty query
    if not query:
        raise ValueError("Empty expression")

    # Additional security checks to prevent malicious patterns
    # Prevent multiple consecutive operators
    if re.search(r'[+\-*/]{2,}', query):
        raise ValueError("Invalid operator sequence")

    # Prevent expressions starting or ending with operators (except minus for negative numbers)
    if re.match(r'^[+*/]', query) or re.search(r'[+\-*/]$', query):
        raise ValueError("Expression cannot start or end with operator")

    try:
        # Use eval with restricted globals and locals for safety
        result = eval(query, {"__builtins__": {}}, {})

        # Ensure result is a number
        if not isinstance(result, (int, float)):
            raise ValueError("Result is not a number")

        return result
    except ZeroDivisionError:
        raise ValueError("Division by zero")
    except (SyntaxError, ValueError) as e:
        raise ValueError("Invalid mathematical expression")

import ast
import operator

def run_user_script(user_script: str):
    # Define allowed operations
    allowed_ops = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
        ast.FloorDiv: operator.floordiv,
        ast.Mod: operator.mod,
        ast.Pow: operator.pow,
        ast.USub: operator.neg,
        ast.UAdd: operator.pos,
        ast.Eq: operator.eq,
        ast.NotEq: operator.ne,
        ast.Lt: operator.lt,
        ast.LtE: operator.le,
        ast.Gt: operator.gt,
        ast.GtE: operator.ge,
        ast.And: lambda x, y: x and y,
        ast.Or: lambda x, y: x or y,
        ast.Not: operator.not_,
    }

    # Define allowed string methods
    allowed_str_methods = {
        'upper', 'lower', 'strip', 'replace', 'split', 'join', 'find', 'count',
        'startswith', 'endswith', 'isdigit', 'isalpha', 'isalnum', 'capitalize'
    }

    # Define allowed built-in functions
    allowed_builtins = {
        'abs', 'min', 'max', 'sum', 'len', 'str', 'int', 'float', 'bool',
        'round', 'pow', 'divmod'
    }

    class SafeEvaluator(ast.NodeVisitor):
        def __init__(self):
            self.variables = {}

        def visit(self, node):
            method = 'visit_' + node.__class__.__name__
            visitor = getattr(self, method, self.generic_visit)
            return visitor(node)

        def generic_visit(self, node):
            raise ValueError(f"Operation not allowed: {type(node).__name__}")

        def visit_Module(self, node):
            result = None
            for stmt in node.body:
                result = self.visit(stmt)
            return result

        def visit_Expr(self, node):
            return self.visit(node.value)

        def visit_Assign(self, node):
            if len(node.targets) != 1:
                raise ValueError("Multiple assignment not allowed")
            target = node.targets[0]
            if not isinstance(target, ast.Name):
                raise ValueError("Only simple variable assignment allowed")
            value = self.visit(node.value)
            self.variables[target.id] = value
            return value

        def visit_Name(self, node):
            if isinstance(node.ctx, ast.Store):
                return node.id
            elif isinstance(node.ctx, ast.Load):
                if node.id in self.variables:
                    return self.variables[node.id]
                elif node.id in allowed_builtins:
                    return eval(node.id)
                else:
                    raise ValueError(f"Undefined variable: {node.id}")

        def visit_Constant(self, node):
            if isinstance(node.value, (int, float, str, bool, type(None))):
                return node.value
            raise ValueError("Unsupported constant type")

        def visit_Num(self, node):  # For Python < 3.8 compatibility
            return node.n

        def visit_Str(self, node):  # For Python < 3.8 compatibility
            return node.s

        def visit_BinOp(self, node):
            left = self.visit(node.left)
            right = self.visit(node.right)
            op_type = type(node.op)
            if op_type in allowed_ops:
                return allowed_ops[op_type](left, right)
            raise ValueError(f"Binary operation not allowed: {op_type.__name__}")

        def visit_UnaryOp(self, node):
            operand = self.visit(node.operand)
            op_type = type(node.op)
            if op_type in allowed_ops:
                return allowed_ops[op_type](operand)
            raise ValueError(f"Unary operation not allowed: {op_type.__name__}")

        def visit_Compare(self, node):
            left = self.visit(node.left)
            for op, comparator in zip(node.ops, node.comparators):
                right = self.visit(comparator)
                op_type = type(op)
                if op_type in allowed_ops:
                    result = allowed_ops[op_type](left, right)
                    if not result:
                        return False
                    left = right
                else:
                    raise ValueError(f"Comparison not allowed: {op_type.__name__}")
            return True

        def visit_BoolOp(self, node):
            op_type = type(node.op)
            if op_type not in allowed_ops:
                raise ValueError(f"Boolean operation not allowed: {op_type.__name__}")

            values = [self.visit(value) for value in node.values]
            if isinstance(node.op, ast.And):
                return all(values)
            elif isinstance(node.op, ast.Or):
                return any(values)

        def visit_Call(self, node):
            if isinstance(node.func, ast.Name):
                func_name = node.func.id
                if func_name in allowed_builtins:
                    args = [self.visit(arg) for arg in node.args]
                    return eval(func_name)(*args)
            elif isinstance(node.func, ast.Attribute):
                obj = self.visit(node.func.value)
                method_name = node.func.attr
                if isinstance(obj, str) and method_name in allowed_str_methods:
                    args = [self.visit(arg) for arg in node.args]
                    return getattr(obj, method_name)(*args)
            raise ValueError("Function call not allowed")

        def visit_List(self, node):
            return [self.visit(item) for item in node.elts]

        def visit_Tuple(self, node):
            return tuple(self.visit(item) for item in node.elts)

        def visit_Dict(self, node):
            result = {}
            for key, value in zip(node.keys, node.values):
                result[self.visit(key)] = self.visit(value)
            return result

        def visit_Subscript(self, node):
            obj = self.visit(node.value)
            key = self.visit(node.slice)
            return obj[key]

        def visit_Index(self, node):  # For Python < 3.9 compatibility
            return self.visit(node.value)

        def visit_Slice(self, node):
            lower = self.visit(node.lower) if node.lower else None
            upper = self.visit(node.upper) if node.upper else None
            step = self.visit(node.step) if node.step else None
            return slice(lower, upper, step)

    try:
        tree = ast.parse(user_script, mode='exec')
        evaluator = SafeEvaluator()
        return evaluator.visit(tree)
    except (SyntaxError, ValueError) as e:
        raise ValueError(f"Script execution failed: {str(e)}")

import re
import ast

def parse_and_calculate(expression: str):
    # Remove whitespace
    expression = expression.strip()

    # Validate input contains only allowed characters
    if not re.match(r'^[0-9+\-*/().\s]+$', expression):
        raise ValueError("Invalid characters in expression")

    # Parse the expression into an AST
    try:
        tree = ast.parse(expression, mode='eval')
    except SyntaxError:
        raise ValueError("Invalid mathematical expression")

    # Define allowed node types for safe evaluation
    allowed_nodes = (ast.Expression, ast.BinOp, ast.UnaryOp, ast.Num, ast.Constant)
    allowed_ops = (ast.Add, ast.Sub, ast.Mult, ast.Div, ast.USub, ast.UAdd)

    def validate_node(node):
        if not isinstance(node, allowed_nodes):
            raise ValueError("Unsafe operation detected")

        if isinstance(node, ast.BinOp):
            if not isinstance(node.op, allowed_ops):
                raise ValueError("Unsafe operator detected")
            validate_node(node.left)
            validate_node(node.right)
        elif isinstance(node, ast.UnaryOp):
            if not isinstance(node.op, allowed_ops):
                raise ValueError("Unsafe operator detected")
            validate_node(node.operand)
        elif isinstance(node, ast.Expression):
            validate_node(node.body)

    # Validate the AST
    validate_node(tree)

    # Safely evaluate the expression
    try:
        result = eval(compile(tree, '<string>', 'eval'))
        return result
    except ZeroDivisionError:
        raise ValueError("Division by zero")
    except Exception:
        raise ValueError("Error evaluating expression")

import ast
