def safe_execute_operation(operation: str):
    # Define allowed operators
    allowed_operators = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
        ast.USub: operator.neg,
        ast.UAdd: operator.pos
    }

    def evaluate_node(node):
        if isinstance(node, ast.Constant):
            if isinstance(node.value, (int, float)):
                return node.value
            else:
                raise ValueError("Only numeric constants allowed")
        elif isinstance(node, ast.Num):  # For Python < 3.8 compatibility
            return node.n
        elif isinstance(node, ast.BinOp):
            left = evaluate_node(node.left)
            right = evaluate_node(node.right)
            op_type = type(node.op)
            if op_type in allowed_operators:
                if op_type == ast.Div and right == 0:
                    raise ZeroDivisionError("Division by zero")
                return allowed_operators[op_type](left, right)
            else:
                raise ValueError("Operator not allowed")
        elif isinstance(node, ast.UnaryOp):
            operand = evaluate_node(node.operand)
            op_type = type(node.op)
            if op_type in allowed_operators:
                return allowed_operators[op_type](operand)
            else:
                raise ValueError("Operator not allowed")
        else:
            raise ValueError("Invalid expression")

    try:
        # Parse the operation string
        tree = ast.parse(operation, mode='eval')

        # Check if the parsed tree contains only allowed nodes
        for node in ast.walk(tree):
            if not isinstance(node, (ast.Expression, ast.Constant, ast.Num, ast.BinOp, ast.UnaryOp, ast.Add, ast.Sub, ast.Mult, ast.Div, ast.USub, ast.UAdd)):
                raise ValueError("Invalid expression")

        # Evaluate the expression
        result = evaluate_node(tree.body)
        return result

    except (SyntaxError, ValueError, ZeroDivisionError) as e:
        raise ValueError(f"Invalid operation: {str(e)}")

