def exec_calculation(calc_string: str) -> str:
    try:
        # Remove whitespace
        calc_string = calc_string.strip()

        # Check if string is empty
        if not calc_string:
            return "Error: Empty expression"

        # Only allow safe characters: digits, operators, parentheses, decimal points
        if not re.match(r'^[0-9+\-*/().\ ]+$', calc_string):
            return "Error: Invalid characters in expression"

        # Parse the expression into an AST
        try:
            node = ast.parse(calc_string, mode='eval')
        except SyntaxError:
            return "Error: Invalid syntax"

        # Define allowed operations
        allowed_ops = {
            ast.Add: operator.add,
            ast.Sub: operator.sub,
            ast.Mult: operator.mul,
            ast.Div: operator.truediv,
            ast.USub: operator.neg,
            ast.UAdd: operator.pos,
        }

        def eval_node(node):
            if isinstance(node, ast.Expression):
                return eval_node(node.body)
            elif isinstance(node, ast.Num):  # For Python < 3.8
                return node.n
            elif isinstance(node, ast.Constant):  # For Python >= 3.8
                if isinstance(node.value, (int, float)):
                    return node.value
                else:
                    raise ValueError("Invalid constant type")
            elif isinstance(node, ast.BinOp):
                left = eval_node(node.left)
                right = eval_node(node.right)
                op = allowed_ops.get(type(node.op))
                if op is None:
                    raise ValueError("Unsupported operation")
                return op(left, right)
            elif isinstance(node, ast.UnaryOp):
                operand = eval_node(node.operand)
                op = allowed_ops.get(type(node.op))
                if op is None:
                    raise ValueError("Unsupported operation")
                return op(operand)
            else:
                raise ValueError("Unsupported node type")

        result = eval_node(node)

        # Handle division by zero
        if result == float('inf') or result == float('-inf'):
            return "Error: Division by zero"

        # Format result
        if isinstance(result, float) and result.is_integer():
            return str(int(result))
        else:
            return str(result)

    except ZeroDivisionError:
        return "Error: Division by zero"
    except (ValueError, TypeError, AttributeError):
        return "Error: Invalid expression"
    except Exception:
        return "Error: Calculation failed"

def run_user_query(query: str) -> str:
    try:
        # Whitelist of allowed operations and functions for quiz calculations
        allowed_names = {
            '__builtins__': {},
            'abs': abs,
            'round': round,
            'min': min,
            'max': max,
            'sum': sum,
            'len': len,
            'int': int,
            'float': float,
            'str': str,
            'bool': bool,
            'True': True,
            'False': False,
            'None': None,
        }

        # Basic input validation
        if not isinstance(query, str):
            return "Error: Invalid input type"

        if len(query) > 1000:
            return "Error: Query too long"

        # Check for dangerous keywords/patterns
        dangerous_patterns = [
            'import', 'exec', 'eval', 'compile', 'open', 'file',
            '__', 'getattr', 'setattr', 'delattr', 'hasattr',
            'globals', 'locals', 'vars', 'dir', 'help',
            'input', 'raw_input', 'reload', 'quit', 'exit'
        ]

        query_lower = query.lower()
        for pattern in dangerous_patterns:
            if pattern in query_lower:
                return "Error: Unauthorized operation"

        # Only allow basic mathematical expressions and safe operations
        allowed_chars = set('0123456789+-*/().,<>=!& |abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ_')
        if not all(c in allowed_chars or c.isspace() for c in query):
            return "Error: Invalid characters in query"

        # Evaluate with restricted environment
        result = eval(query, allowed_names, {})
        return str(result)

    except ZeroDivisionError:
        return "Error: Division by zero"
    except SyntaxError:
        return "Error: Invalid syntax"
    except NameError:
        return "Error: Undefined variable or function"
    except TypeError:
        return "Error: Type error in expression"
